    uint32_t inDim = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    uint32_t outDim = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int32_t maxDim = attrs->GetAttrPointer<int32_t>(0);
    int32_t meanDim = attrs->GetAttrPointer<int32_t>(1);

    // After linear, shape is (batch, outDim). After max on maxDim (keepdim=True),
    // shape becomes (batch, 1) if maxDim=1, or (1, outDim) if maxDim=0.
    // Then after mean on meanDim (keepdim=True) and subtract, shape stays same.
