    // But we also need to account for the subtraction that broadcasts? actually output shape same as after max.
    // Let's compute output total elements.
    uint32_t totalLength = (maxDim == 0) ? outDim : batch; // but after max, only one dimension left? Wait: keepdim=True, so shape becomes (1, outDim) or (batch,1). So total elements = outDim or batch.
    // However the output after subtract and gelu is same shape. So we set totalLength accordingly.
    // For simplicity, we set totalLength as the product of the non-reduced dimensions.
    // But the kernel will need to know batch and outDim to handle the reduction operations.
    // We'll store batch and outDim in tiling.
    tiling.set_totalLength(totalLength);
    tiling.set_batch(batch);
    tiling.set_outDim(outDim);

    // Tile the totalLength (we treat it as 1D for data copy)
    uint32_t maxTile = UB_BUDGET_BYTES / (5 * sizeof(float)); // estimate 5 vectors
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);
    uint32_t tileLen = (totalLength < maxTile) ? totalLength : maxTile;
    tileLen = AlignDown(tileLen, ALIGN_ELEMS);
    if (tileLen == 0) tileLen = totalLength;

    uint32_t numTiles = CeilDiv(totalLength, tileLen);
    uint32_t blockDim = (numTiles < 8) ? 8 : numTiles;
    if (blockDim > 24) blockDim = 24;
    context->SetBlockDim(blockDim);

    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_maxDim(maxDim);
    tiling.set_meanDim(meanDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

